import { MikroOrmModuleOptions } from '@mikro-orm/nestjs';
import { ConfigService } from '@nestjs/config';

export interface DatabaseConfig {
  client: 'postgresql' | 'mongodb' | 'mysql' | 'sqlite' | 'mssql';
  connectionString: string;
  dbName?: string;
  entities: string[];
  debug?: boolean;
  migrations?: {
    path: string;
    pathTs: string;
  };
}

export const getMikroOrmConfig = (
  configService: ConfigService,
): MikroOrmModuleOptions => {
  const connectionString = configService.get<string>('DATABASE_URL', '');
  let client = configService.get<DatabaseConfig['client']>('DB_CLIENT');

  // Detect client from connection string if not explicitly provided
  if (!client && connectionString) {
    if (
      connectionString.startsWith('postgresql://') ||
      connectionString.startsWith('postgres://')
    ) {
      client = 'postgresql';
    } else if (connectionString.startsWith('mysql://')) {
      client = 'mysql';
    } else if (
      connectionString.startsWith('sqlserver://') ||
      connectionString.startsWith('mssql://')
    ) {
      client = 'mssql';
    } else if (connectionString.startsWith('mongodb://')) {
      client = 'mongodb';
    } else if (
      connectionString.endsWith('.sqlite') ||
      connectionString.startsWith('sqlite://')
    ) {
      client = 'sqlite';
    }
  }

  // Default to postgresql if still not determined
  client = client || 'postgresql';

  const baseOptions: any = {
    entities: ['./dist/**/*.entity.js'],
    entitiesTs: ['./src/**/*.entity.ts'],
    debug: configService.get<boolean>('DB_DEBUG', false),
    migrations: {
      path: './migrations',
      pathTs: './src/migrations',
    },
  };

  if (connectionString) {
    const parsed = parseConnectionString(connectionString, client);
    return {
      ...baseOptions,
      ...parsed,
      driver: client,
    };
  }

  // Fallback to individual env vars
  const host = configService.get<string>('DB_HOST', 'localhost');
  const port = configService.get<number>('DB_PORT', getDefaultPort(client));
  const user = configService.get<string>('DB_USER', '');
  const password = configService.get<string>('DB_PASSWORD', '');
  const dbName = configService.get<string>(
    'DB_NAME',
    client === 'sqlite' ? './data.sqlite' : 'storesync',
  );

  return {
    ...baseOptions,
    driver: client,
    host,
    port,
    user,
    password,
    dbName,
  };
};

function parseConnectionString(
  connectionString: string,
  client: DatabaseConfig['client'],
) {
  if (client === 'sqlite') {
    const dbName = connectionString.replace(/^sqlite:\/\//, '');
    return { dbName };
  }

  if (client === 'mongodb') {
    return { clientUrl: connectionString };
  }

  if (client === 'mssql') {
    try {
      const cleanUrl = connectionString
        .replace(/^sqlserver:\/\//, 'http://')
        .replace(/^mssql:\/\//, 'http://');
      const url = new URL(cleanUrl);
      return {
        host: url.hostname,
        port: parseInt(url.port) || 1433,
        user: decodeURIComponent(url.username),
        password: decodeURIComponent(url.password),
        dbName: url.pathname.replace(/^\//, ''),
      };
    } catch {
      return { clientUrl: connectionString };
    }
  }

  try {
    const url = new URL(connectionString);
    return {
      host: url.hostname,
      port: parseInt(url.port) || getDefaultPort(client),
      user: decodeURIComponent(url.username),
      password: decodeURIComponent(url.password),
      dbName: url.pathname.replace(/^\//, ''),
    };
  } catch {
    return { clientUrl: connectionString };
  }
}

function getDefaultPort(client: DatabaseConfig['client']): number {
  switch (client) {
    case 'postgresql':
      return 5432;
    case 'mysql':
      return 3306;
    case 'mssql':
      return 1433;
    case 'mongodb':
      return 27017;
    default:
      return 5432;
  }
}

import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';

async function bootstrap() {
  const app = await NestFactory.create(AppModule);
  await app.listen(process.env.PORT ?? 3002);
}
bootstrap();

import { Injectable, NotFoundException } from '@nestjs/common';
import { InjectRepository } from '@mikro-orm/nestjs';
import { EntityRepository } from '@mikro-orm/core';
import { Order, OrderStatus } from '../entities';

@Injectable()
export class OrdersService {
  constructor(
    @InjectRepository(Order)
    private readonly orderRepository: EntityRepository<Order>,
  ) {}

  async findAll(): Promise<Order[]> {
    return this.orderRepository.findAll({ populate: ['customer'] } as any);
  }

  async findOne(id: number): Promise<Order> {
    const order = await this.orderRepository.findOne(
      { id } as any,
      { populate: ['customer'] } as any,
    );
    if (!order) {
      throw new NotFoundException(`Order with id ${id} not found`);
    }
    return order;
  }

  async findByCustomer(customerId: number): Promise<Order[]> {
    return this.orderRepository.find(
      { customer: customerId } as any,
      { populate: ['customer'] } as any,
    );
  }

  async findByStatus(status: OrderStatus): Promise<Order[]> {
    return this.orderRepository.find(
      { status } as any,
      { populate: ['customer'] } as any,
    );
  }

  async create(orderData: Partial<Order>): Promise<Order> {
    const order = this.orderRepository.create({
      ...orderData,
      orderNumber: this.generateOrderNumber(),
    } as any);
    await this.orderRepository.getEntityManager().persistAndFlush(order);
    return order;
  }

  async updateStatus(id: number, status: OrderStatus): Promise<Order> {
    const order = await this.findOne(id);
    order.status = status;
    await this.orderRepository.getEntityManager().flush();
    return order;
  }

  async update(id: number, orderData: Partial<Order>): Promise<Order> {
    const order = await this.findOne(id);
    this.orderRepository.assign(order, orderData);
    await this.orderRepository.getEntityManager().flush();
    return order;
  }

  async delete(id: number): Promise<void> {
    const order = await this.findOne(id);
    await this.orderRepository.getEntityManager().removeAndFlush(order);
  }

  private generateOrderNumber(): string {
    const timestamp = Date.now().toString(36).toUpperCase();
    const random = Math.random().toString(36).substring(2, 6).toUpperCase();
    return `ORD-${timestamp}${random}`;
  }
}

import {
  Controller,
  Get,
  Post,
  Put,
  Delete,
  Body,
  Param,
  Query,
  ParseIntPipe,
} from '@nestjs/common';
import { ApiTags, ApiOperation, ApiResponse } from '@nestjs/swagger';
import { ProductsService } from './products.service';
import { Product } from '../entities';

@ApiTags('products')
@Controller('products')
export class ProductsController {
  constructor(private readonly productsService: ProductsService) {}

  @Get()
  @ApiOperation({ summary: 'Get all products' })
  @ApiResponse({ status: 200, description: 'Return all products' })
  async findAll(): Promise<Product[]> {
    return this.productsService.findAll();
  }

  @Get(':id')
  @ApiOperation({ summary: 'Get product by id' })
  @ApiResponse({ status: 200, description: 'Return the product' })
  @ApiResponse({ status: 404, description: 'Product not found' })
  async findOne(@Param('id', ParseIntPipe) id: number): Promise<Product> {
    return this.productsService.findOne(id);
  }

  @Get('sku/:sku')
  @ApiOperation({ summary: 'Get product by SKU' })
  @ApiResponse({ status: 200, description: 'Return the product' })
  async findBySku(@Param('sku') sku: string): Promise<Product | null> {
    return this.productsService.findBySku(sku);
  }

  @Get('category/:category')
  @ApiOperation({ summary: 'Get products by category' })
  @ApiResponse({ status: 200, description: 'Return products in category' })
  async findByCategory(
    @Param('category') category: string,
  ): Promise<Product[]> {
    return this.productsService.findByCategory(category);
  }

  @Post()
  @ApiOperation({ summary: 'Create a new product' })
  @ApiResponse({ status: 201, description: 'Product created' })
  async create(@Body() productData: Partial<Product>): Promise<Product> {
    return this.productsService.create(productData);
  }

  @Put(':id')
  @ApiOperation({ summary: 'Update a product' })
  @ApiResponse({ status: 200, description: 'Product updated' })
  async update(
    @Param('id', ParseIntPipe) id: number,
    @Body() productData: Partial<Product>,
  ): Promise<Product> {
    return this.productsService.update(id, productData);
  }

  @Delete(':id')
  @ApiOperation({ summary: 'Delete a product' })
  @ApiResponse({ status: 200, description: 'Product deleted' })
  async delete(@Param('id', ParseIntPipe) id: number): Promise<void> {
    return this.productsService.delete(id);
  }
}

import { Injectable, NotFoundException } from '@nestjs/common';
import { InjectRepository } from '@mikro-orm/nestjs';
import { EntityRepository } from '@mikro-orm/core';
import { Product } from '../entities';

@Injectable()
export class ProductsService {
  constructor(
    @InjectRepository(Product)
    private readonly productRepository: EntityRepository<Product>,
  ) {}

  async findAll(): Promise<Product[]> {
    return this.productRepository.findAll();
  }

  async findOne(id: number): Promise<Product> {
    const product = await this.productRepository.findOne({ id });
    if (!product) {
      throw new NotFoundException(`Product with id ${id} not found`);
    }
    return product;
  }

  async findBySku(sku: string): Promise<Product | null> {
    return this.productRepository.findOne({ sku });
  }

  async findByCategory(category: string): Promise<Product[]> {
    return this.productRepository.find({ category });
  }

  async create(productData: Partial<Product>): Promise<Product> {
    const product = this.productRepository.create(productData as any);
    await this.productRepository.getEntityManager().persistAndFlush(product);
    return product;
  }

  async update(id: number, productData: Partial<Product>): Promise<Product> {
    const product = await this.findOne(id);
    this.productRepository.assign(product, productData);
    await this.productRepository.getEntityManager().flush();
    return product;
  }

  async delete(id: number): Promise<void> {
    const product = await this.findOne(id);
    await this.productRepository.getEntityManager().removeAndFlush(product);
  }
}

import {
  Injectable,
  NotFoundException,
  ConflictException,
} from '@nestjs/common';
import { InjectRepository } from '@mikro-orm/nestjs';
import { EntityRepository } from '@mikro-orm/core';
import { User, UserRole } from '../entities';

@Injectable()
export class UsersService {
  constructor(
    @InjectRepository(User)
    private readonly userRepository: EntityRepository<User>,
  ) {}

  async findAll(): Promise<User[]> {
    return this.userRepository.findAll();
  }

  async findOne(id: number): Promise<User> {
    const user = await this.userRepository.findOne({ id });
    if (!user) {
      throw new NotFoundException(`User with id ${id} not found`);
    }
    return user;
  }

  async findByEmail(email: string): Promise<User | null> {
    return this.userRepository.findOne({ email });
  }

  async findByRole(role: UserRole): Promise<User[]> {
    return this.userRepository.find({ role });
  }

  async create(userData: Partial<User>): Promise<User> {
    const existingUser = await this.findByEmail(userData.email!);
    if (existingUser) {
      throw new ConflictException(
        `User with email ${userData.email} already exists`,
      );
    }

    const user = this.userRepository.create(userData as any);
    await this.userRepository.getEntityManager().persistAndFlush(user);
    return user;
  }

  async update(id: number, userData: Partial<User>): Promise<User> {
    const user = await this.findOne(id);
    this.userRepository.assign(user, userData);
    await this.userRepository.getEntityManager().flush();
    return user;
  }

  async delete(id: number): Promise<void> {
    const user = await this.findOne(id);
    await this.userRepository.getEntityManager().removeAndFlush(user);
  }

  async validateUser(email: string, password: string): Promise<User | null> {
    const user = await this.findByEmail(email);
    if (user && user.password === password) {
      return user;
    }
    return null;
  }
}
